import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq
import torch


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = tuple(np.round(np.array(n["coords"], dtype=float), 6))
        coord_to_idx[coord] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(tuple(np.round(np.array(nb, dtype=float), 6)))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        coord_nb = tuple(np.round(np.array(nb, dtype=float), 6))
        j = coord_to_idx.get(coord_nb)
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class Explorer:
    def __init__(self):
        self.step_count = 0
        self.history = []
        self.prev_pos = None
        self.prev_move_dir = None

    def _update_history(self, coord):
        self.history.append(np.array(coord, dtype=float))
        if len(self.history) > 20:
            self.history.pop(0)

    def select_action(self, obs):
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]

        if not neighbors:
            return None

        self.step_count += 1
        steps_remaining = max(0, 128 - self.step_count)

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        first_step = [None] * N
        order = [i for i in range(N) if dist[i] < float('inf') and i != r_idx]
        order.sort(key=lambda i: dist[i])
        for j in order:
            p = prev[j]
            if p == r_idx:
                first_step[j] = j
            else:
                fs = first_step[p] if p is not None else None
                first_step[j] = fs if fs is not None else j

        node_to_neighbor_idx = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(tuple(np.round(np.array(nb, dtype=float), 6)))
            if j is not None:
                node_to_neighbor_idx[j] = idx

        scores = np.zeros(len(neighbors), dtype=float)
        history_set = set(tuple(np.round(h, 6)) for h in self.history)

        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf') or d < 1e-6:
                continue
            fs = first_step[j]
            if fs is None:
                continue
            nb_idx = node_to_neighbor_idx.get(fs)
            if nb_idx is None:
                continue

            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue

            val = utility / (d + 3.6)

            if bool(nodes[j].get("visited", False)):
                val *= 0.2

            coord_j = tuple(np.round(np.array(nodes[j]["coords"], dtype=float), 6))
            if coord_j in history_set:
                val *= 0.65

            est_steps = d / 3.2
            if est_steps > steps_remaining:
                val = 0.0
            elif est_steps > steps_remaining * 0.75:
                val *= 0.25

            scores[nb_idx] += val

        if self.prev_move_dir is not None:
            for idx, nb in enumerate(neighbors):
                move_dir = np.array(nb, dtype=float) - robot_pos
                move_dir_norm = np.linalg.norm(move_dir)
                if move_dir_norm > 1e-6:
                    move_dir = move_dir / move_dir_norm
                    dot = np.dot(move_dir, -self.prev_move_dir)
                    if dot > 0.7:
                        scores[idx] *= 0.3

        best_idx = int(np.argmax(scores)) if len(scores) > 0 else None
        if best_idx is not None and scores[best_idx] > 1e-9:
            target = tuple(float(x) for x in neighbors[best_idx])
            self.prev_pos = robot_pos.copy()
            self.prev_move_dir = (np.array(target, dtype=float) - robot_pos)
            pn = np.linalg.norm(self.prev_move_dir)
            if pn > 1e-6:
                self.prev_move_dir = self.prev_move_dir / pn
            else:
                self.prev_move_dir = None
            self._update_history(target)
            return target

        # Fallback: nearest unvisited node via graph
        unvisited = []
        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf'):
                continue
            if not bool(nodes[j].get("visited", False)):
                fs = first_step[j]
                if fs is None:
                    continue
                nb_idx = node_to_neighbor_idx.get(fs)
                if nb_idx is not None:
                    unvisited.append((d, nb_idx))
        if unvisited:
            unvisited.sort(key=lambda x: x[0])
            target = tuple(float(x) for x in neighbors[unvisited[0][1]])
            self.prev_pos = robot_pos.copy()
            self.prev_move_dir = (np.array(target, dtype=float) - robot_pos)
            pn = np.linalg.norm(self.prev_move_dir)
            if pn > 1e-6:
                self.prev_move_dir = self.prev_move_dir / pn
            else:
                self.prev_move_dir = None
            self._update_history(target)
            return target

        # Final fallback: neighbor farthest from history
        best_score = -1.0
        best_idx = 0
        for i, nb in enumerate(neighbors):
            s = 0.0
            for h in self.history:
                s += np.linalg.norm(np.array(nb, dtype=float) - h)
            if s > best_score:
                best_score = s
                best_idx = i
        target = tuple(float(x) for x in neighbors[best_idx])
        self.prev_pos = robot_pos.copy()
        self.prev_move_dir = (np.array(target, dtype=float) - robot_pos)
        pn = np.linalg.norm(self.prev_move_dir)
        if pn > 1e-6:
            self.prev_move_dir = self.prev_move_dir / pn
        else:
            self.prev_move_dir = None
        self._update_history(target)
        return target


def run_episode(env, explorer):
    obs = env.reset()
    for step in range(128):
        target = explorer.select_action(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info["done"]:
            break
    return env.get_metrics()


def discover_episodes(data_path):
    eval_config_path = os.path.join(data_path, "eval_config.json")
    if os.path.exists(eval_config_path):
        with open(eval_config_path, "r") as f:
            eval_config = json.load(f)
        if "episodes" in eval_config:
            return eval_config["episodes"]
        if "map_list" in eval_config:
            return [{"map_path": m, "env_type": "unknown"} for m in eval_config["map_list"]]
    # Scan maps_eval directory
    episodes = []
    maps_dir = os.path.join(data_path, "maps_eval")
    if os.path.isdir(maps_dir):
        for sub in ["room", "tunnel", "outdoor"]:
            subdir = os.path.join(maps_dir, sub)
            if os.path.isdir(subdir):
                for fname in sorted(os.listdir(subdir)):
                    if fname.endswith(".png"):
                        episodes.append({
                            "map_path": os.path.join("maps_eval", sub, fname),
                            "env_type": sub
                        })
    return episodes


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        ckpt = torch.load(ckpt_path, map_location="cpu")
        print("Loaded checkpoint version:", ckpt.get("version", "unknown"))
    else:
        print("No checkpoint found, using heuristic")

    episodes = discover_episodes(args.data_path)
    per_episode = []
    per_type_stats = {}

    for ep in episodes:
        map_path = os.path.join(args.data_path, ep["map_path"])
        env_type = ep.get("env_type", "unknown")
        env = ExplorationEnv(map_path=map_path)
        explorer = Explorer()
        metrics = run_episode(env, explorer)
        explored_rate = metrics["explored_rate"]
        travel_distance = metrics["travel_distance"]
        success = 1 if explored_rate > 0.9999 else 0

        per_episode.append({
            "map_path": ep["map_path"],
            "env_type": env_type,
            "success": success,
            "travel_distance": travel_distance,
            "explored_rate": explored_rate
        })

        if env_type not in per_type_stats:
            per_type_stats[env_type] = {
                "explored_rates": [],
                "success_dists": [],
                "count": 0,
                "successes": 0
            }
        per_type_stats[env_type]["explored_rates"].append(explored_rate)
        per_type_stats[env_type]["count"] += 1
        if success:
            per_type_stats[env_type]["successes"] += 1
            per_type_stats[env_type]["success_dists"].append(travel_distance)

    total_episodes = len(episodes)
    explored_rate = float(np.mean([ep["explored_rate"] for ep in per_episode])) if total_episodes > 0 else 0.0
    success_rate = float(np.mean([ep["success"] for ep in per_episode])) if total_episodes > 0 else 0.0
    all_success_dists = []
    for ep in per_episode:
        if ep["success"]:
            all_success_dists.append(ep["travel_distance"])
    travel_distance = float(np.mean(all_success_dists)) if all_success_dists else 0.0

    per_type = {}
    for env_type, stats in per_type_stats.items():
        count = stats["count"]
        per_type[env_type] = {
            "explored_rate": float(np.mean(stats["explored_rates"])) if count > 0 else 0.0,
            "travel_distance": float(np.mean(stats["success_dists"])) if stats["success_dists"] else 0.0,
            "success_rate": stats["successes"] / count if count > 0 else 0.0
        }

    result = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": total_episodes
    }

    os.makedirs(os.path.dirname(args.output), exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)
    print("Wrote results to", args.output)


if __name__ == "__main__":
    main()
